    }

    #[test]
    fn sanitize_tool_name_preserves_internal_quotes() {
        // Quotes in the middle are NOT stripped — only surrounding pair.
        assert_eq!(sanitize_tool_name("my\"tool"), "my\"tool");
    }

    #[test]
    fn sanitize_tool_name_single_quotes_not_stripped() {
